#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct ControlPackageValidationReport { pub diagnostics: Vec<ControlPackageValidationDiagnostic> }
impl ControlPackageValidationReport { pub fn new() -> Self { Self { diagnostics: Vec::new() } } pub fn is_valid(&self) -> bool { !self.diagnostics.iter().any(|diagnostic| diagnostic.severity == ControlPackageValidationSeverity::Error) } pub fn push(&mut self, diagnostic: ControlPackageValidationDiagnostic) { self.diagnostics.push(diagnostic); } pub fn extend(&mut self, report: ControlPackageValidationReport) { self.diagnostics.extend(report.diagnostics); } pub fn has_reason(&self, reason: ControlPackageValidationReason) -> bool { self.diagnostics.iter().any(|diagnostic| diagnostic.reason == reason) } }
impl Default for ControlPackageValidationReport { fn default() -> Self { Self::new() } }

#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct ControlPackageValidationDiagnostic { pub diagnostic_id: ControlDiagnosticId, pub severity: ControlPackageValidationSeverity, pub scope: ControlPackageValidationScope, pub path: ControlPackageValidationPath, pub reason: ControlPackageValidationReason, pub message: String }
impl ControlPackageValidationDiagnostic { pub fn package(package_id: ControlPackageId, reason: ControlPackageValidationReason, message: impl Into<String>) -> Self { Self::new(ControlPackageValidationScope::Package { package_id }, ControlPackageValidationPath::new("package"), reason, message) } pub fn kind(control_kind_id: ControlKindId, reason: ControlPackageValidationReason, message: impl Into<String>) -> Self { Self::new(ControlPackageValidationScope::Kind { control_kind_id }, ControlPackageValidationPath::new("control_kind"), reason, message) } pub fn new(scope: ControlPackageValidationScope, path: ControlPackageValidationPath, reason: ControlPackageValidationReason, message: impl Into<String>) -> Self { Self { diagnostic_id: ControlDiagnosticId::new(format!("runenwerk.ui.controls.validation.{}", reason.as_snake_case())), severity: ControlPackageValidationSeverity::Error, scope, path, reason, message: message.into() } } }

#[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
