#[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub enum ControlPackageValidationReason { MissingPackageMetadata, MissingKindMetadata, MissingSchema, MissingKernel, MissingFixture, MissingDiagnostic, MissingMigration, MissingStory, MissingRoute, MissingCapability, MissingTargetProfile, MissingMountEvidence, DuplicatePackageId, DuplicateControlKindId, DuplicateSchemaRef, DuplicateKernelId, DuplicateFixtureId, DuplicateDiagnosticId, DuplicateMigrationId, DuplicateStoryId, DuplicateRouteRequirement, InvalidDeprecation, InvalidMigrationVersion, InvalidMountEligibility, UnsupportedTargetProfile, UnresolvedReference, RenderEvidenceMissing, BudgetEvidenceMissing }
impl ControlPackageValidationReason { pub const fn as_snake_case(self) -> &'static str { match self { Self::MissingPackageMetadata => "missing_package_metadata", Self::MissingKindMetadata => "missing_kind_metadata", Self::MissingSchema => "missing_schema", Self::MissingKernel => "missing_kernel", Self::MissingFixture => "missing_fixture", Self::MissingDiagnostic => "missing_diagnostic", Self::MissingMigration => "missing_migration", Self::MissingStory => "missing_story", Self::MissingRoute => "missing_route", Self::MissingCapability => "missing_capability", Self::MissingTargetProfile => "missing_target_profile", Self::MissingMountEvidence => "missing_mount_evidence", Self::DuplicatePackageId => "duplicate_package_id", Self::DuplicateControlKindId => "duplicate_control_kind_id", Self::DuplicateSchemaRef => "duplicate_schema_ref", Self::DuplicateKernelId => "duplicate_kernel_id", Self::DuplicateFixtureId => "duplicate_fixture_id", Self::DuplicateDiagnosticId => "duplicate_diagnostic_id", Self::DuplicateMigrationId => "duplicate_migration_id", Self::DuplicateStoryId => "duplicate_story_id", Self::DuplicateRouteRequirement => "duplicate_route_requirement", Self::InvalidDeprecation => "invalid_deprecation", Self::InvalidMigrationVersion => "invalid_migration_version", Self::InvalidMountEligibility => "invalid_mount_eligibility", Self::UnsupportedTargetProfile => "unsupported_target_profile", Self::UnresolvedReference => "unresolved_reference", Self::RenderEvidenceMissing => "render_evidence_missing", Self::BudgetEvidenceMissing => "budget_evidence_missing" } } }

impl ControlKindDescriptor { pub fn validate_contract(&self) -> ControlPackageValidationReport { let mut report = ControlPackageValidationReport::new(); if self.display_name.trim().is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingKindMetadata, "control kind display name must not be empty")); } if self.description.trim().is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingKindMetadata, "control kind description must not be empty")); } if self.target_profiles.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingTargetProfile, "control kind must name at least one target profile")); } if self.diagnostic_ids.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingDiagnostic, "control kind must name at least one diagnostic")); } if self.fixture_ids.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingFixture, "control kind must name at least one fixture")); } if self.route_requirements.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingRoute, "control kind must name at least one route requirement")); } push_duplicate_kind_values(&mut report, &self.control_kind_id, "target_profile", self.target_profiles.iter().map(|profile| profile.as_str().to_owned()), ControlPackageValidationReason::UnsupportedTargetProfile); push_duplicate_kind_values(&mut report, &self.control_kind_id, "route", self.route_requirements.iter().map(|route| route.route_id.as_str().to_owned()), ControlPackageValidationReason::DuplicateRouteRequirement); push_duplicate_kind_values(&mut report, &self.control_kind_id, "story", self.story_ids.iter().map(|story| story.as_str().to_owned()), ControlPackageValidationReason::DuplicateStoryId); if let ControlMountEligibility::RequiresEvidence { story_ids, render_evidence_ids, budget_evidence_ids } = &self.mount_eligibility { if story_ids.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::MissingMountEvidence, "mount eligibility requires at least one story")); } if render_evidence_ids.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::RenderEvidenceMissing, "mount eligibility requires render evidence")); } if budget_evidence_ids.is_empty() { report.push(ControlPackageValidationDiagnostic::kind(self.control_kind_id.clone(), ControlPackageValidationReason::BudgetEvidenceMissing, "mount eligibility requires budget evidence")); } } report } }
